def transition(state, action):
    s = dict(state)
    name = action.get("name")
    params = action.get("params") or {}

    specialties = list(s.get("specialties", []))
    waiting = [dict(v) for v in s.get("waiting", [])]
    routed = {k: [dict(v) for v in vs] for k, vs in s.get("routed", {}).items()}
    completed = [dict(v) for v in s.get("completed", [])]
    next_id = int(s.get("next_id", 1))

    def clamp_priority(p):
        if not isinstance(p, int) or isinstance(p, bool):
            return 3
        return max(1, min(5, p))

    # urgent-first, then arrival order (FIFO within a priority band)
    def order_key(v):
        return (-v["priority"], v["id"])

    if name == "enqueue":
        # New visit joins the waiting pool. Specialty defaults to a round-robin
        # over the configured specialties so unparameterized rollouts stay live.
        specialty = params.get("specialty")
        if specialty not in specialties:
            specialty = (specialties[(next_id - 1) % len(specialties)]
                         if specialties else "general")
        visit = {
            "id": next_id,
            "specialty": specialty,
            "priority": clamp_priority(params.get("priority")),
            "status": "waiting",
        }
        waiting.append(visit)
        next_id += 1

    elif name == "route":
        # Move a waiting visit into its specialty's provider queue. Pick by
        # explicit id if given, else the most-urgent / earliest waiting visit.
        target = None
        vid = params.get("id")
        if vid is not None:
            for v in waiting:
                if v["id"] == vid:
                    target = v
                    break
        if target is None and waiting:
            target = sorted(waiting, key=order_key)[0]
        if target is not None:
            waiting = [v for v in waiting if v["id"] != target["id"]]
            spec = target["specialty"]
            if spec not in routed:
                routed[spec] = []
            routed[spec].append(dict(target, status="routed"))

    elif name == "complete":
        # A provider finishes the head of a specialty queue. Pick the named
        # specialty if it has anyone queued, else the queue holding the single
        # most-urgent routed visit across all specialties.
        spec = params.get("specialty")
        queue_spec = spec if (spec in routed and routed[spec]) else None
        if queue_spec is None:
            best = None  # (priority, -id, specialty)
            for k, vs in routed.items():
                if vs:
                    head = sorted(vs, key=order_key)[0]
                    cand = (head["priority"], -head["id"], k)
                    if best is None or cand > best:
                        best = cand
            if best is not None:
                queue_spec = best[2]
        if queue_spec is not None and routed.get(queue_spec):
            head = sorted(routed[queue_spec], key=order_key)[0]
            routed[queue_spec] = [v for v in routed[queue_spec]
                                  if v["id"] != head["id"]]
            completed.append({
                "id": head["id"],
                "specialty": head["specialty"],
                "priority": head["priority"],
                "status": "completed",
            })

    # noop / unrecognized actions fall through, leaving the queues untouched.

    s["waiting"] = waiting
    s["routed"] = routed
    s["completed"] = completed
    s["next_id"] = next_id
    s["num_waiting"] = len(waiting)
    s["num_routed"] = sum(len(vs) for vs in routed.values())
    s["num_completed"] = len(completed)
    return s

