def perceive(data):
    fields = {}
    if isinstance(data, dict):
        fields = dict(data)
    else:
        for part in str(data).replace(",", ";").split(";"):
            if "=" in part:
                k, v = part.split("=", 1)
                fields[k.strip()] = v.strip()
            elif ":" in part:
                k, v = part.split(":", 1)
                fields[k.strip()] = v.strip()
    out = {}
    spec = fields.get("specialty")
    if spec is not None:
        out["intake_specialty"] = str(spec).strip().lower()
    pri = fields.get("priority")
    if pri is not None:
        try:
            p = int(pri)
        except (ValueError, TypeError):
            p = 3
        out["intake_priority"] = max(1, min(5, p))
    return out
